// VertexParserInit initializes any static state used to implement VertexParser. By default the
// static state used to implement the parser is lazily initialized during the first call to
// NewVertexParser(). You can call this function if you wish to initialize the static state ahead
// of time.
func VertexParserInit() {
	staticData := &VertexParserParserStaticData
	staticData.once.Do(vertexparserParserInit)
}

// NewVertexParser produces a new parser instance for the optional input antlr.TokenStream.
func NewVertexParser(input antlr.TokenStream) *VertexParser {
	VertexParserInit()
	this := new(VertexParser)
	this.BaseParser = antlr.NewBaseParser(input)
	staticData := &VertexParserParserStaticData
	this.Interpreter = antlr.NewParserATNSimulator(this, staticData.atn, staticData.decisionToDFA, staticData.PredictionContextCache)
	this.RuleNames = staticData.RuleNames
	this.LiteralNames = staticData.LiteralNames
	this.SymbolicNames = staticData.SymbolicNames
	this.GrammarFileName = "VertexParser.g4"

	return this
}

